export class ProtocolValidationError extends Error {
    constructor(message, code = "INVALID_FRAME") {
        super(message);
        this.code = code;
        this.name = "ProtocolValidationError";
    }
}
export function validateRegisterFrame(frame) {
    const record = frame;
    if (record.type !== "app_register" && record.type !== "backend_register") {
        throw new ProtocolValidationError(`Expected type "app_register" or "backend_register", got "${String(record.type)}"`, "INVALID_FRAME");
    }
    if (record.type === "app_register") {
        if (typeof record.access_token !== "string" || record.access_token.trim() === "") {
            throw new ProtocolValidationError(`Frame requires non-empty access_token`, "INVALID_TOKEN");
        }
        if (typeof record.terminal_label !== "string" || record.terminal_label.trim() === "") {
            throw new ProtocolValidationError(`Frame requires non-empty terminal_label`, "INVALID_FRAME");
        }
        return;
    }
    if (typeof record.backend_id !== "string" || record.backend_id.trim() === "") {
        throw new ProtocolValidationError(`Frame requires non-empty backend_id`, "INVALID_FRAME");
    }
    if (typeof record.backend_label !== "string" || record.backend_label.trim() === "") {
        throw new ProtocolValidationError(`Frame requires non-empty backend_label`, "INVALID_FRAME");
    }
    // PKI auth: every backend_register should carry an Ed25519 public key.
    // The router enforces this at the message-dispatch layer (see
    // `tryImportEd25519PublicKey` in router.ts) so we keep validateRegisterFrame
    // permissive here — it just type-checks the well-known fields. The router
    // emits a specific `INVALID_PUBLIC_KEY` error frame when the key is missing
    // or malformed, which is the path the existing test suite relies on.
}
export function getStringField(frame, field) {
    const value = frame[field];
    if (typeof value !== "string" || value.trim() === "") {
        throw new ProtocolValidationError(`Frame requires string field "${field}"`, "INVALID_FRAME");
    }
    return value;
}
